// Determine if the 'Surplus List' field was updated
const record = $input.item.json;
const fields = record.fields || {};

// Check if Surplus List field exists and has content
if (fields["Surplus List"] && fields["Surplus List"].length > 0) {
  const timestamp = new Date().toISOString();

  return {
    json: {
      recordId: record.id,
      auctionName: fields["Auction Name"] || "Unknown Auction",
      county: fields["County"] || "Unknown County",
      surplusList: fields["Surplus List"],
      message: `Surplus List updated for auction at ${timestamp}`,
      action: 'surplus_list_updated'
    }
  };
} else {
  // If no Surplus List, skip processing
  return [];
}
